import argparse
import json
import logging
from collections import deque
from pathlib import Path

import networkx as nx
from pyvis.network import Network
from scipy.sparse import load_npz


logger = logging.getLogger(__name__)


def parse_seed_args(seed_args: list[str]) -> list[str]:
    seeds = []
    for seed_arg in seed_args:
        seeds.extend(seed.strip() for seed in seed_arg.split(",") if seed.strip())
    return seeds


def load_graph_artifacts(graph_dir: Path):
    matrix_path = graph_dir / "graph_mat.npz"
    song_to_idx_path = graph_dir / "song_to_idx.json"
    idx_to_song_path = graph_dir / "idx_to_song.json"

    missing_paths = [
        path for path in (matrix_path, song_to_idx_path, idx_to_song_path)
        if not path.is_file()
    ]
    if missing_paths:
        missing = ", ".join(str(path) for path in missing_paths)
        raise FileNotFoundError(f"Missing graph artifact(s): {missing}")

    graph_mat = load_npz(matrix_path).tocsr()
    with open(song_to_idx_path, "r") as f:
        song_to_idx = json.load(f)
    with open(idx_to_song_path, "r") as f:
        idx_to_song = json.load(f)

    return graph_mat, song_to_idx, idx_to_song


def get_song_id(idx_to_song: dict[str, str], node_idx: int) -> str:
    return idx_to_song[str(node_idx)]


def get_filtered_neighbors(graph_mat, node_idx: int, min_weight: int, top_k: int):
    row = graph_mat.getrow(node_idx)
    neighbors = [
        (int(neighbor_idx), int(weight))
        for neighbor_idx, weight in zip(row.indices, row.data)
        if int(weight) >= min_weight and int(neighbor_idx) != node_idx
    ]
    neighbors.sort(key=lambda item: item[1], reverse=True)
    return neighbors[:top_k]


def select_neighborhood(
    graph_mat,
    seed_indices: list[int],
    depth: int,
    min_weight: int,
    max_nodes: int,
    max_edges: int,
    top_k_per_node: int,
):
    selected_nodes = set(seed_indices)
    selected_edges = {}
    queue = deque((seed_idx, 0) for seed_idx in seed_indices)
    expanded_nodes = set()

    while queue and len(selected_nodes) < max_nodes and len(selected_edges) < max_edges:
        node_idx, node_depth = queue.popleft()
        if node_idx in expanded_nodes or node_depth >= depth:
            continue

        expanded_nodes.add(node_idx)
        neighbors = get_filtered_neighbors(
            graph_mat,
            node_idx,
            min_weight=min_weight,
            top_k=top_k_per_node,
        )

        for neighbor_idx, weight in neighbors:
            if len(selected_edges) >= max_edges:
                break

            if neighbor_idx not in selected_nodes:
                if len(selected_nodes) >= max_nodes:
                    continue
                selected_nodes.add(neighbor_idx)
                queue.append((neighbor_idx, node_depth + 1))

            edge_key = tuple(sorted((node_idx, neighbor_idx)))
            selected_edges[edge_key] = max(weight, selected_edges.get(edge_key, 0))

    return selected_nodes, selected_edges


def build_networkx_graph(selected_nodes, selected_edges, idx_to_song):
    graph = nx.Graph()

    for node_idx in selected_nodes:
        song_id = get_song_id(idx_to_song, node_idx)
        graph.add_node(
            node_idx,
            label=song_id,
            title=f"Song ID: {song_id}<br>Matrix index: {node_idx}",
        )

    for (source_idx, target_idx), weight in selected_edges.items():
        graph.add_edge(
            source_idx,
            target_idx,
            weight=weight,
            value=weight,
            title=f"Shared playlists: {weight}",
        )

    return graph


def render_html(graph, output_path: Path, open_browser: bool):
    output_path.parent.mkdir(parents=True, exist_ok=True)
    net = Network(notebook=False, height="850px", width="100%")
    net.from_nx(graph)
    net.toggle_physics(True)
    net.write_html(str(output_path), open_browser=open_browser)


def positive_int(value: str) -> int:
    parsed = int(value)
    if parsed <= 0:
        raise argparse.ArgumentTypeError("must be greater than 0")
    return parsed


def non_negative_int(value: str) -> int:
    parsed = int(value)
    if parsed < 0:
        raise argparse.ArgumentTypeError("must be greater than or equal to 0")
    return parsed


def main():
    parser = argparse.ArgumentParser(
        description="Visualize a filtered neighborhood from a sparse song graph."
    )
    parser.add_argument(
        "graph_dir",
        type=Path,
        help="Directory containing graph_mat.npz, song_to_idx.json, and idx_to_song.json.",
    )
    parser.add_argument(
        "--seed",
        action="append",
        required=True,
        help="Seed song id to visualize. Can be repeated or comma-separated.",
    )
    parser.add_argument(
        "--depth",
        type=non_negative_int,
        default=1,
        help="Neighborhood expansion depth from the seed song ids.",
    )
    parser.add_argument(
        "--min-weight",
        type=positive_int,
        default=1,
        help="Minimum edge weight to include.",
    )
    parser.add_argument(
        "--max-nodes",
        type=positive_int,
        default=250,
        help="Maximum nodes to render.",
    )
    parser.add_argument(
        "--max-edges",
        type=positive_int,
        default=1000,
        help="Maximum edges to render.",
    )
    parser.add_argument(
        "--top-k-per-node",
        type=positive_int,
        default=50,
        help="Maximum highest-weight neighbors expanded per node.",
    )
    parser.add_argument(
        "--output",
        type=Path,
        default=Path("graph_subset.html"),
        help="HTML file to write.",
    )
    parser.add_argument(
        "--open-browser",
        action="store_true",
        help="Open the generated HTML file in a browser.",
    )
    parser.add_argument(
        "--log-level",
        default="INFO",
        choices=("DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"),
        help="Logging verbosity.",
    )

    args = parser.parse_args()

    logging.basicConfig(
        level=getattr(logging, args.log_level),
        format="%(asctime)s %(levelname)s [%(name)s] %(message)s",
    )

    seeds = parse_seed_args(args.seed)
    graph_mat, song_to_idx, idx_to_song = load_graph_artifacts(args.graph_dir)

    missing_seeds = [seed for seed in seeds if seed not in song_to_idx]
    if missing_seeds:
        missing = ", ".join(missing_seeds)
        raise ValueError(f"Seed song id(s) not found in song_to_idx.json: {missing}")

    seed_indices = [int(song_to_idx[seed]) for seed in seeds]
    selected_nodes, selected_edges = select_neighborhood(
        graph_mat,
        seed_indices=seed_indices,
        depth=args.depth,
        min_weight=args.min_weight,
        max_nodes=args.max_nodes,
        max_edges=args.max_edges,
        top_k_per_node=args.top_k_per_node,
    )

    if not selected_edges:
        raise ValueError(
            "No edges matched the requested filters. Try lowering --min-weight, "
            "increasing --depth, or using a different --seed."
        )

    logger.info(
        "Rendering %s nodes and %s edges from %s seed(s)",
        len(selected_nodes),
        len(selected_edges),
        len(seed_indices),
    )
    graph = build_networkx_graph(selected_nodes, selected_edges, idx_to_song)
    render_html(graph, args.output, args.open_browser)
    logger.info("Wrote %s", args.output)


if __name__ == "__main__":
    main()
